// ── 1. HSC Invoice ────────────────────────────────────────────────────────────

describe("Real-World Accuracy – HSC Invoice #2927935", () => {
  let r: DataLiftResponse;
  beforeAll(() => {
    r = parser.parse(HSC_INVOICE_TEXT, { documentType: "invoice" });
  });

  // Document type
  it("classifies as invoice", () => {
    expect(r.metadata.documentType).toBe("invoice");
  });

  // Supplier
  it("extracts vendor name (Hydraulic Supply Company)", () => {
    expect(r.supplier.name).toMatch(/hydraulic\s*supply/i);
  });
  it("extracts vendor phone 954-845-1040", () => {
    expect(r.supplier.contact.phone).toMatch(/954.?845.?1040/);
  });
  it("extracts vendor email CREDIT@HYDRAULIC-SUPPLY.COM", () => {
    expect(r.supplier.contact.email).toMatch(/credit@hydraulic-supply\.com/i);
  });

  // Transaction
  it("extracts invoice number 2927935", () => {
    expect(r.transaction.invoiceNumber).toMatch(/2927935/);
  });
  it("extracts invoice date 2023-11-20", () => {
    // date may be stored as ISO or localised string
    expect(r.transaction.invoiceDate).toMatch(/2023.*(11|20)|11.*20.*2023/);
  });
  it("extracts order number 3022293", () => {
    const ref =
      r.transaction.purchaseOrderNumber ?? r.transaction.referenceNumber ?? "";
    expect(ref + JSON.stringify(r.transaction)).toMatch(/3022293/);
  });
  it("extracts PO reference 2687261635692 or similar", () => {
    const po =
      r.transaction.purchaseOrderNumber ?? r.transaction.referenceNumber ?? "";
    expect(po + JSON.stringify(r.transaction)).toMatch(
      /2687|261635692|3022293/,
    );
  });
  it("detects payment term PREPAID", () => {
    expect(r.transaction.paymentTerms ?? "").toMatch(/prepaid/i);
  });
  it("extracts currency USD", () => {
    expect(r.transaction.currency).toBe("USD");
  });

  // Totals – exact values from page 2 of the invoice
  it("extracts subtotal $29.45", () => {
    expect(r.totals.subtotal).toBeCloseTo(29.45, 1);
  });
  it("extracts total tax $1.78", () => {
    expect(r.totals.totalTax).toBeCloseTo(1.78, 1);
  });
  it("extracts grand total (credit card charged) $31.23", () => {
    expect(r.totals.grandTotal).toBeCloseTo(31.23, 1);
  });
  it("amount due is 0.00 or grand total 31.23 (already paid)", () => {
    // balanceDue should be 0 (paid in full) or grandTotal 31.23
    expect([0, 31.23]).toContain(
      Math.round((r.totals.balanceDue ?? r.totals.grandTotal) * 100) / 100,
    );
  });

  // Line items – 4 items across 2 pages
  it("extracts at least 3 line items", () => {
    expect(r.parts.length).toBeGreaterThanOrEqual(3);
  });
  it("first item contains BLUE MONSTER or TEF", () => {
    const descs = r.parts.map((p) =>
      (p.description ?? p.itemName ?? "").toUpperCase(),
    );
    expect(
      descs.some(
        (d) => d.includes("BLUE") || d.includes("TEF") || d.includes("70885"),
      ),
    ).toBe(true);
  });
  it("line item unit prices are positive", () => {
    r.parts.forEach((p) => {
      if (p.unitPrice !== undefined) expect(p.unitPrice).toBeGreaterThan(0);
    });
  });
  it("sum of line item extended prices ≈ subtotal $29.45 (±$1)", () => {
    const sum = r.parts.reduce(
      (acc, p) => acc + (p.totalAmount ?? p.unitPrice ?? 0),
      0,
    );
    if (sum > 0) expect(sum).toBeCloseTo(29.45, 0);
  });
});

