describe("Real-World Accuracy – Cross-document sanity", () => {
  const docs = [
    { label: "HSC Invoice", text: HSC_INVOICE_TEXT, type: "invoice" as const },
    { label: "TMS Receipt", text: TMS_RECEIPT_TEXT, type: "receipt" as const },
    {
      label: "TMS Cash Sale",
      text: TMS_CASH_SALE_TEXT,
      type: "invoice" as const,
    },
    {
      label: "NAPA Invoice",
      text: NAPA_INVOICE_TEXT,
      type: "invoice" as const,
    },
    {
      label: "Lowes Receipt",
      text: LOWES_RECEIPT_TEXT,
      type: "receipt" as const,
    },
  ];

  docs.forEach(({ label, text, type }) => {
    describe(label, () => {
      let r: DataLiftResponse;
      beforeAll(() => {
        r = parser.parse(text, { documentType: type });
      });

      it("does not throw", () => {
        expect(() => parser.parse(text, { documentType: type })).not.toThrow();
      });

      it("grandTotal is positive", () => {
        expect(r.totals.grandTotal).toBeGreaterThan(0);
      });

      it("grandTotal ≥ subtotal (no impossible inversion)", () => {
        if (r.totals.subtotal && r.totals.subtotal > 0) {
          expect(r.totals.grandTotal).toBeGreaterThanOrEqual(
            r.totals.subtotal * 0.9,
          );
        }
      });

      it("has a supplier name", () => {
        expect(r.supplier.name.length).toBeGreaterThan(1);
      });

      it("currency is set", () => {
        expect(r.transaction.currency).toBeTruthy();
      });

      it("extraction timestamp is present and valid", () => {
        expect(
          new Date(r.metadata.extractionTimestamp).getFullYear(),
        ).toBeGreaterThan(2020);
      });
    });
  });
});
